nta.declaration:
//  global declarations .

const int nbVar :=5;
const int MaxInput := 4; // per node
const int NbStates := 4; // 0 == F, 1 == M, 2 == B, 3 == N

const int sF:=0; const int sM:=1; const int sB:=2; const int sN:=3; //node states
const int pF:=0; const int pP:=1; const int pA:=2; //attacker position
const int cU:=0; const int cR:=1; const int cK:=2; // knode type

broadcast chan startCh; // start sychro


const int NU := -1; //nout used

const int nbNodes := 2; // component number

typedef struct {
    int[NU,nbNodes-1] node_id; // input node id,  -1 not used
    int[NU,2] attack_position; //  0 == Functional, 1 == Path, 2 == Access
    int[NU,7] cost[NbStates][NbStates];  // attacker node state, attacked node target state,  -1 not possible, external node state, target local state
} input_t; // input description, for each interaction


typedef struct {
    int[0,nbNodes-1] node_id;
    int[0, 2] node_type; // 0 == user space component , 1 == root space component, 2 == kernel
    int[0,MaxInput-1] nb_Inputs;
    int[NU,7] cost[NbStates][NbStates];  //  local attacker node state, attacked node target state,  -1 not possible, external node state, target local state
    bool locSecretVar[nbVar]; // if true, secret to be retrived here
    int[NU,7] costVarGet, costVarTransf;
    input_t in[MaxInput]; // too much
} node_t; // node description, for topology


// sF:=0; const int sM:=1; const int sB:=2; const int sN:=3; //node states

const node_t topology[nbNodes] := {
    {0,cU,0, {{NU,NU,NU,NU},{NU,NU,2,1},{NU,5,NU,4},{NU,NU,NU,NU}}, {true, false, true,false, false},4,1, // node 0
        {{  // node 0 input 0 
            NU, NU,{{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        },
        {  // node 0 input 1 
            NU, NU,{{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        },
        {  // node 0 input 2
            NU, NU, {{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        },
        {  // node 0 input 3
            NU, NU, {{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        }}
    },
    {1,cU,1, {{NU,NU,NU,NU},{NU,NU,2,1},{NU,5,NU,4},{NU,NU,NU,NU}}, {false, true, false,true, false},4,1,// node 1 
        {{  // node 0 input 0
            0, pF, {{NU,NU,NU,NU},{NU,4,2,1},{NU,5,3,1},{NU,NU,NU,1}}
        },
        {  // node 0 input 1
            NU, NU, {{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        }, 
        {  // node 0 input 2
            NU, NU, {{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        },
        {  // node 0 input 3
            NU, NU, {{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU},{NU,NU,NU,NU}}
        }} 
    } // list of input nodes of node 1
} ;    


typedef struct {
    int[0,NbStates-1] location; // 0 == F, 1 == M, 2 == B, 3 == N
    bool locKnowledgeVar[nbVar]; 
} nodeState_t;  // node state, init all = F == 1

nodeState_t nodeState[nbNodes]:={ 
    {sM , {false, false, false,false, false}},
    {sF , {false, false, false,false, false}}
} ;

const int maxCosts:=20;
int costs:=0;



int[NU,maxCosts] getMinInputCost(int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state, int[0,NbStates-1] target_state) {  // node qui est visé et son état acuel et son état visé
    int cost:=-1; int attackerState:=-1; int costTmp:=-1;
    int[0,nbNodes] nbInputs; 
    nbInputs := topology[node_id].nb_Inputs;
	for(i : int[0,MaxInput-1] ) {
	    if (i<(nbInputs)) {
            attackerState:=nodeState[topology[node_id].in[i].node_id].location;
            costTmp:=topology[node_id].in[i].cost[attackerState][target_state];
            if ((costTmp>=0) and (costTmp>cost)) cost:=costTmp;
        } 
	}
    if ( (cost+costs)<= maxCosts )	return cost; else return -1;
}

void updateNode (int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state,int[0,NbStates-1] target_state) {
    int tmp:=getMinInputCost(node_id, source_state,target_state);
    if (tmp >0) costs:=costs+tmp;
    nodeState[node_id].location:=target_state;
}


int[NU,maxCosts] getLocalCost(int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state, int[0,NbStates-1] target_state) {  // node qui est visé et son état acuel et son état visé
    int cost:=topology[node_id].cost[source_state][target_state];
    if ( (cost>=0) and ((cost+costs)<= maxCosts ))	return cost; else return -1;
}

void updateLocal (int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state,int[0,NbStates-1] target_state) {
    int tmp:=getLocalCost(node_id, source_state,target_state);
    if (tmp >0) costs:=costs+tmp;
    nodeState[node_id].location:=target_state;
}


int[NU,maxCosts] LocalVarCost(int[NU,nbNodes-1] node_id) {
    int[NU,maxCosts] cost;
    for(i : int[0,nbVar-1] ) {
        if ((!nodeState[node_id].locKnowledgeVar[i]) and topology[node_id].locSecretVar[i] ) {
            cost:=topology[node_id].costVarGet;
            if ((cost >=0) and (cost+costs)<=maxCosts) return cost;
        }
    };
    return -1;
}

void setLocalVar(int[NU,nbNodes-1] node_id){
       int[NU,maxCosts] cost;
    for(i : int[0,nbVar-1] ) {
        if ((!nodeState[node_id].locKnowledgeVar[i]) and topology[node_id].locSecretVar[i] ) {
            cost:=topology[node_id].costVarGet;
            if ((cost >=0) and (cost+costs)<=maxCosts) {
                costs:=costs+cost; nodeState[node_id].locKnowledgeVar[i]:=true; return;
            }
        }
    }; 
}

nta.system:
// Place template instantiations here.

App0 = AppUser(0);
App1 = AppUser(1);
Go=Start();

// List one or more processes to be composed into a system.
system   Go, App0, App1;
